import os
import sys
import shutil
import subprocess
import tempfile
import hashlib
from pathlib import Path
from zipfile import ZipFile, ZIP_DEFLATED

ROOT = Path(__file__).resolve().parent
REQ = ROOT / "requirements.txt"
DIST = ROOT / "dist"
BUILD = ROOT / "build"
ARTIFACTS = ROOT / "artifacts"
VENV = ROOT / ".venv"
DEFAULT_ARTIFACT_NAME = "deployment_package.zip"

DEFAULT_EXCLUDES = {
    ".git", ".hg", ".svn",
    ".venv", "venv", "env",
    "__pycache__", ".pytest_cache", ".mypy_cache", ".ruff_cache", ".coverage",
    "dist", "build", "artifacts",
    ".idea", ".vscode",
    ".DS_Store",
}

TEXT_EXTS = {".py", ".txt", ".md", ".cfg", ".ini", ".toml", ".yaml", ".yml", ".json", ".sh", ".ps1", ".bat"}


def log(msg: str) -> None:
    sys.stdout.write(msg + "\n")
    sys.stdout.flush()


def run(cmd, cwd=ROOT, env=None) -> None:
    log("+ " + " ".join(map(str, cmd)))
    subprocess.run(list(map(str, cmd)), cwd=str(cwd), env=env, check=True)


def is_windows() -> bool:
    return os.name == "nt"


def venv_python(venv_dir: Path) -> Path:
    if is_windows():
        return venv_dir / "Scripts" / "python.exe"
    return venv_dir / "bin" / "python"


def venv_pip(venv_dir: Path) -> Path:
    if is_windows():
        return venv_dir / "Scripts" / "pip.exe"
    return venv_dir / "bin" / "pip"


def ensure_venv(venv_dir: Path) -> None:
    py = venv_python(venv_dir)
    if py.exists():
        return
    log(f"Creating venv at {venv_dir}")
    run([sys.executable, "-m", "venv", str(venv_dir)])


def requirements_fingerprint(req_file: Path) -> str:
    if not req_file.exists():
        return ""
    data = req_file.read_bytes()
    return hashlib.sha256(data).hexdigest()


def read_cached_fingerprint(venv_dir: Path) -> str:
    fp = venv_dir / ".requirements.sha256"
    if fp.exists():
        return fp.read_text(encoding="utf-8").strip()
    return ""


def write_cached_fingerprint(venv_dir: Path, digest: str) -> None:
    (venv_dir / ".requirements.sha256").write_text(digest, encoding="utf-8")


def install_deps(venv_dir: Path, req_file: Path) -> None:
    if not req_file.exists():
        log("requirements.txt not found; skipping dependency install")
        return

    new_fp = requirements_fingerprint(req_file)
    old_fp = read_cached_fingerprint(venv_dir)

    py = venv_python(venv_dir)
    pip = venv_pip(venv_dir)

    run([str(py), "-m", "pip", "install", "--upgrade", "pip", "setuptools", "wheel"])

    if new_fp and new_fp == old_fp:
        log("requirements.txt unchanged; skipping dependency install")
        return

    log("Installing dependencies")
    run([str(pip), "install", "--disable-pip-version-check", "--no-input", "-r", str(req_file)])
    if new_fp:
        write_cached_fingerprint(venv_dir, new_fp)


def run_tests(venv_dir: Path) -> None:
    py = venv_python(venv_dir)

    env = os.environ.copy()
    env["PYTHONUNBUFFERED"] = "1"

    try:
        run([str(py), "-m", "pytest", "-q"], env=env)
        return
    except subprocess.CalledProcessError:
        raise
    except Exception:
        pass

    try:
        run([str(py), "-m", "unittest", "discover", "-s", "tests", "-p", "test*.py"], env=env)
    except subprocess.CalledProcessError:
        raise
    except Exception:
        log("No test runner found or tests failed to start")
        raise


def should_exclude(path: Path, rel: Path, excludes: set[str]) -> bool:
    parts = set(rel.parts)
    if any(p in excludes for p in parts):
        return True
    name = path.name
    if name in excludes:
        return True
    return False


def collect_files(root: Path, excludes: set[str]) -> list[Path]:
    files = []
    for p in root.rglob("*"):
        if p.is_dir():
            continue
        rel = p.relative_to(root)
        if should_exclude(p, rel, excludes):
            continue
        files.append(p)
    return files


def package_zip(root: Path, out_zip: Path, excludes: set[str]) -> None:
    out_zip.parent.mkdir(parents=True, exist_ok=True)
    if out_zip.exists():
        out_zip.unlink()

    files = collect_files(root, excludes)

    with ZipFile(out_zip, "w", compression=ZIP_DEFLATED, compresslevel=6) as zf:
        for f in files:
            rel = f.relative_to(root)
            zf.write(str(f), arcname=str(rel).replace(os.sep, "/"))

    log(f"Created artifact: {out_zip} ({out_zip.stat().st_size} bytes)")


def clean_dirs(*paths: Path) -> None:
    for p in paths:
        if p.exists():
            shutil.rmtree(p, ignore_errors=True)


def main() -> int:
    artifact_name = os.environ.get("ARTIFACT_NAME", DEFAULT_ARTIFACT_NAME)
    artifact_path = ARTIFACTS / artifact_name

    excludes = set(DEFAULT_EXCLUDES)
    extra_excludes = os.environ.get("PACKAGE_EXCLUDES", "").strip()
    if extra_excludes:
        for item in extra_excludes.split(","):
            item = item.strip()
            if item:
                excludes.add(item)

    try:
        clean = os.environ.get("CLEAN", "0").lower() in {"1", "true", "yes"}
        if clean:
            clean_dirs(DIST, BUILD, ARTIFACTS)

        ensure_venv(VENV)
        install_deps(VENV, REQ)
        run_tests(VENV)

        package_zip(ROOT, artifact_path, excludes)
        return 0
    except subprocess.CalledProcessError as e:
        return e.returncode or 1
    except Exception:
        return 1


if __name__ == "__main__":
    raise SystemExit(main())